const preferences=CookiesEntity.getInstance().init("preferences"),loader=new Loader(document.currentScript.getAttribute("data-files"),preferences.get("advanced")?.accuracy||"precise").load().then(()=>{const queue=EventQueue.getInstance();queue.queue({target:$("#login"),event:"submit",handler:event=>{event.preventDefault(),login(new GithubAuthenticator({username:$("#login .username").val(),token:$("#login .token").val(),headers:GithubAPI.getHeaders()}))}}),queue.queue({event:"ready",handler:()=>{if(GithubAuthenticator.isLoggedIn()){const auth=preferences.get("auth");login(new GithubAuthenticator({username:auth.username,token:auth.token,headers:GithubAPI.getHeaders()}))}}}),queue.queue({target:[$("header#main #user .logout"),$("#sidebar .logout"),$("#comments .logout")],event:"click",handler:logout}),(new MainQueue).queue(),queue.queue({event:"ready",handler:()=>(new GithubCommentsCounterView).render()}),queue.fire().then(async()=>{$("body > .wrapper").get(0).removeAttribute("style");const promises=[];promises.push(()=>new Promise((resolve)=>{history.scrollRestoration="manual",$(window).on("beforeunload",()=>{$(window).scrollTop(0)}),resolve()})),promises.push(()=>new Promise((resolve)=>{$("body").attr("data-loaded",!0).removeClass("loading"),window.requestTimeout(()=>resolve(),1250)})),promises.push(()=>new Promise((resolve)=>{$("#preloader").remove(),window.requestTimeout(()=>resolve(),1750)}));for(const promise of promises)await promise();(new LazyLoading).run().then(()=>(new Snapping).run())})});function login(authenticator){return authenticator.attach(new AuthenticatorObserver({promise:authenticator.login()}))}function logout(){const authenticator=new GithubAuthenticator({headers:GithubAPI.getHeaders()});return authenticator.attach(new AuthenticatorObserver({promise:authenticator.logout()}))}